import os
from prometheus_client import start_http_server, Gauge

# Define the Prometheus gauge metrics
db_username = Gauge('database_username', 'Database username', ['host'])
db_password = Gauge('database_password', 'Database password', ['host'])
db_host = Gauge('database_host', 'Database host')
db_connection_string = Gauge('database_connection_string', 'Database connection string')

def export_metrics():
    # Securely retrieve database credentials from environment variables
    db_user = os.getenv('DB_USERNAME')
    db_pass = os.getenv('DB_PASSWORD')
    db_host_val = os.getenv('DB_HOST')
    db_conn_str = os.getenv('DB_CONNECTION_STRING')

    if not all([db_user, db_pass, db_host_val, db_conn_str]):
        raise ValueError("Missing database credentials")

    # Export metrics with labels
    db_username.labels(host=db_host_val).set(1)
    db_password.labels(host=db_host_val).set(1)  # Note: This is insecure to expose passwords in metrics
    db_host.set_to_current_time()
    db_connection_string.labels(host=db_host_val).set(1)

if __name__ == '__main__':
    # Start up the server to expose the metrics.
    start_http_server(8000)
    print("Prometheus metrics server started on port 8000")

    while True:
        export_metrics()